export const meta = {
  name: 'qa-semantic-search',
  description: 'Execute semantic search for QA workflow',
  phases: [
    { title: 'Semantic Search', detail: 'Search knowledge files for relevant sections' }
  ]
}

phase('Semantic Search')

const result = await agent(`
You are executing the semantic search step of the QA workflow for nabledge-6.

## Task
Execute the semantic search defined in workflows/semantic-search.md for the following query:

Query: "エラーが発生したときにエラー画面を表示したり、ログを出力する仕組みはどうなっている？（処理方式: ウェブアプリケーション）（目的: 仕組み・動作を理解したい）"

## Instructions

Read the file at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/workflows/semantic-search.md

Then follow the semantic-search.md workflow exactly to:
1. List candidate knowledge pages from the knowledge directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/
2. Select relevant pages based on the query
3. For each selected page, identify relevant sections (high/partial)

For page listing, use the Glob tool to find all .json files under the knowledge directory.
For reading page content, use the Read tool.

## Output Format
Return a JSON object with this exact structure:
{
  "selected_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why excluded>"}
  ],
  "selected_sections": [
    {"file": "<full file path>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ],
  "excluded_sections": [
    {"file": "<full file path>", "section_id": "<sN>", "reason": "<why excluded>"}
  ]
}

Be thorough - look at all knowledge files related to error handling, exception handling, logging, web application error screens in Nablarch.
`, {label: 'semantic-search', schema: {
  type: 'object',
  properties: {
    selected_pages: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          path: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['path', 'reason']
      }
    },
    excluded_pages: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          path: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['path', 'reason']
      }
    },
    selected_sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          file: { type: 'string' },
          section_id: { type: 'string' },
          relevance: { type: 'string', enum: ['high', 'partial'] },
          reason: { type: 'string' }
        },
        required: ['file', 'section_id', 'relevance', 'reason']
      }
    },
    excluded_sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          file: { type: 'string' },
          section_id: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['file', 'section_id', 'reason']
      }
    }
  },
  required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
}})

return result
